+            // Retry helper for transient GitHub API errors (503, 502, etc.)
+            const MAX_RETRIES = 3;
+            const RETRY_BASE_DELAY_MS = 2000; // 2s base delay with exponential backoff
+            async function withRetry(fn, label = 'API call') {
+              for (let attempt = 1; attempt <= MAX_RETRIES; attempt++) {
+                try {
+                  return await fn();
+                } catch (err) {
+                  const status = err.status || err.response?.status;
+                  const isTransient = status === 502 || status === 503 || status === 504;
+                  if (isTransient && attempt < MAX_RETRIES) {
+                    const delayMs = RETRY_BASE_DELAY_MS * Math.pow(2, attempt - 1);
+                    core.warning(`${label} returned ${status}, retrying in ${delayMs}ms (attempt ${attempt}/${MAX_RETRIES})`);
+                    await new Promise(r => setTimeout(r, delayMs));
+                  } else {
+                    throw err;
+                  }
+                }
+              }
+            }
